    // [Claude] Task: generic onEmbedCall — forwards all Amplenote API calls directly to app
    // Prompt: "simplify onEmbedCall to generic pass-through, remove manual argument mapping"
    // Date: 2026-03-16 | Model: claude-4.6-opus-high-thinking
    /**
     * Central message-passing bridge between the dashboard React embed and the
     * Amplenote host app. Every method call on the `app` Proxy in the embed
     * resolves here via `window.callAmplenotePlugin(method, ...args)`.
     *
     * Custom actions (configure, init) run plugin-specific logic. All other
     * calls are forwarded directly to the Amplenote app interface — callers
     * must pass arguments matching the real Amplenote API signatures.
     *
     * @param {object} app - Amplenote app interface
     * @param {string} actionType - Method name or custom action identifier
     * @param {...*} args - Positional arguments from the embed call
     * @returns {Promise<*>} Resolves to the action result, or `{ error }` on failure.
     */
    async onEmbedCall(app, actionType, ...args) {
      setLoggingEnabled(app.settings[SETTING_KEYS.CONSOLE_LOGGING]);
      try {
        switch (actionType) {
          case "attachNoteMedia":
            const noteHandle = { uuid: app.context.noteUUID };
            logIfEnabled(`[plugin] attachNoteMedia called \u2014 uploading to plugin note ${noteHandle.uuid}`);
            const result = await app.attachNoteMedia(noteHandle, args[1]);
            logIfEnabled(`[plugin] attachNoteMedia result:`, result ? "(URL received)" : "(no URL)");
            return result;
          case "configure":
            return await this._handleConfigure(app, args[0]);
          case "init":
            return await fetchDashboardData(app);
          default:
            if (typeof app[actionType] === "function") {
              return await app[actionType](...args);
            }
            logIfEnabled(`Unknown embed action: ${actionType}`);
            return null;
        }
      } catch (error) {
        logIfEnabled(`onEmbedCall error (${actionType}):`, error);
        return { error: error.message };
      }
    },
